text:
        logger.error(f"[ChatMessageStream] NEW CHAT: Template not found at {template_path}")
        return jsonify({"error": "Template file not found"}), 404

    try:
        with open(template_path, "r", encoding="utf-8") as f:
            template_data = json.load(f)
            node_map = template_data.get("data", {})
            if initial_chat_name == "Untitled Chat":
                initial_chat_name = template_data.get("name", "Untitled Chat")
            if not node_map:
                logger.error(f"[ChatMessageStream] NEW CHAT: Template {template_path} missing 'data'.")
                return jsonify({"error": "Invalid template structure (missing 'data')"}), 500
        logger.info(f"[ChatMessageStream] Loaded node_map from template: {pending_template}")
    except json.JSONDecodeError:
        logger.error(f"[ChatMessageStream] NEW CHAT: Template invalid JSON: {template_path}")
        return jsonify({"error": "Invalid template file format"}), 500
    except Exception as e:
        logger.error(f"[ChatMessageStream] NEW CHAT: Error reading template {template_path}: {e}")
        return jsonify({"error": "Could not read template file"}), 500

    ch = {}
    _apply_initial_faiss_selection(start_node=node_key, node_map_payload=node_map, chat_history_payload=ch)
    if node_key not in ch:
        ch[node_key] = {
            "type": "Chat",
            "messages": [],
            "model": node_map.get(node_key, {}).get("selected_model"),
            "temperature": get_model_and_temp(node_map.get(node_key, {}).get("selected_model"))[1],
            "index": node_map.get(node_key, {}).get("index"),
        }
    node_data_hist = ch[node_key]

# EXISTING
else:
    logger.info(f"[ChatMessageStream] EXISTING chat session (ID: {request_chat_id}).")
    current_chat_id = request_chat_id
    st = load_chat_state(user_id, current_chat_id)
    if not st:
        logger.error(f"[ChatMessageStream] EXISTING CHAT: Invalid chat_id '{current_chat_id}'.")
        return jsonify({"error": "Invalid chat_id"}), 400
    if st.get("user_id") != user_id:
        logger.warning(f"[ChatMessageStream] EXISTING CHAT: Access denied user {user_id} chat {current_chat_id}.")
        return jsonify({"error": "Access denied"}), 403

    ch = st.get("chat_history", {})
    node_map = st.get("nodes", {})
    initial_chat_name = st.get("name", "Untitled Chat")
    node_data_hist = ch.get(node_key)
    if not node_data_hist or node_data_hist.get("type") != "Chat":
        logger.warning(f"[ChatMessageStream] EXISTING CHAT: Invalid node key '{node_key}' or not Chat.")
        return jsonify({"error": "Invalid node_key or node is not Chat"}), 400
    logger.info(f"[ChatMessageStream] EXISTING CHAT: Verified node '{node_key}' as Chat.")

# -------------------------------------------------------------------------
# Dynamic tool: allow the model to add a missing guideline to the FAISS
# selection (only when not all guidelines are currently loaded).
# -------------------------------------------------------------------------
faiss_node_key_for_chat = _find_faiss_store_node_key(node_key, node_map)
guideline_add_tool_definition: Dict[str, Any] | None = None
guideline_label_to_path: Dict[str, str] = {}
guideline_label_canonical: Dict[str, str] = {}
try:
    guideline_mapping = load_guideline_mapping()
    if isinstance(guideline_mapping, dict):
        for path, label in guideline_mapping.items():
            if not isinstance(path, str) or not path.strip():
                continue
            if not isinstance(label, str) or not label.strip():
                continue
            key = label.strip().lower()
            guideline_label_to_path[key] = _canonicalize_faiss_path(path.strip())
            guideline_label_canonical.setdefault(key, label.strip())

    if faiss_node_key_for_chat and guideline_label_to_path:
        current_paths = _get_current_faiss_paths(
            faiss_node_key=faiss_node_key_for_chat,
            node_map_payload=node_map,
            chat_history_payload=ch,
        )
        current_set = {_canonicalize_faiss_path(p) for p in current_paths}

        missing_labels: List[str] = []
        if isinstance(guideline_mapping, dict):
            for path, label in guideline_mapping.items():
                norm_path = _canonicalize_faiss_path(path)
                if norm_path in current_set:
                    continue
                if isinstance(label, str) and label.strip():
                    missing_labels.append(label.strip())

        if missing_labels:
            guideline_add_tool_definition = _build_add_guideline_tool_definition(missing_labels)
except Exception as e:
    logger.warning("[ChatMessageStream] Failed to build add_guideline_to_context tool: %s", e)
    guideline_add_tool_definition = None
    guideline_label_to_path = {}
    guideline_label_canonical = {}

# Usage check
if False and not can_user_send_prompt(user_id):
    wait_mins = get_minutes_until_next_prompt(user_id)
    logger.warning(f"[ChatMessageStream] Usage limit. Wait {wait_mins} minutes.")

    plan = "unknown"
    if db and User:
        try:
            user = db.session.get(User, user_id)
            if user:
                plan = user.plan or "unknown"
        except Exception as e:
            logger.error(f"Fetch user plan failed: {e}", exc_info=True)

    if plan == "trial":
        msg_text = "Trial limit reached. Upgrade plan."
    else:
        msg_text = f"You're sending a bit too many prompts too quickly. Please wait {wait_mins} minute{'s' if wait_mins != 1 else ''}."

    def usage_limit_error_stream():
        yield _sse_event("error", {"message": msg_text, "plan": plan})
